noncompliant:
bool checkValue();

int main() {
  if (checkValue) { // Noncompliant: using function name without () or &
    // This checks function address, not return value
  }
  return 0;
}

compliant:
bool checkValue();

int main() {
  if (checkValue()) { // Compliant: calling function
    // This checks the return value
  }
  return 0;
}
